import { withDb } from "./db.mjs";
import { RULES, qualifies, ownersOf, signalsOf } from "./derive.mjs";

function factsFromDoc(doc) {
  return {
    account: { accountId: doc._id, name: doc.name, tier: doc.tier, region: doc.region },
    contract: doc.contract,
    contacts: doc.contacts,
    invoices: doc.invoices,
    shipments: doc.shipments,
    regulatoryFlags: doc.regulatoryFlags,
    supportCases: doc.supportCases,
    usage: doc.usage
  };
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const result = await client.query("SELECT doc FROM accounts LIMIT 1");
    const doc = result.rows[0]?.doc;
    if (!doc) throw new Error("No account facts found");

    const facts = factsFromDoc(doc);
    const accountId = facts.account.accountId;
    const requestId = doc.request?.requestId || `req-${accountId}`;
    const qualifying = qualifies(facts, now);
    const signals = signalsOf(facts, now);
    const owners = qualifying ? ownersOf(facts, now) : [];
    const status = qualifying ? RULES.escalationStatus : RULES.monitorStatus;
    const nextStep = qualifying ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;

    await client.query("BEGIN");
    try {
      await client.query("DELETE FROM workflow_state");
      await client.query("DELETE FROM owner_tasks");
      await client.query("DELETE FROM customer_messages");
      await client.query("DELETE FROM audit_events");

      await client.query(
        "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, facts.account.name || accountId, status, nextStep, riskSummary]
      );

      for (const owner of owners) {
        await client.query(
          "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
          [requestId, accountId, owner, `${owner} recovery owner task`, now, "open"]
        );
      }

      if (qualifying) {
        await client.query(
          "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
          [
            requestId,
            accountId,
            "Our team has opened a priority recovery effort on your account and will follow up shortly."
          ]
        );
        await client.query(
          "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
          [requestId, accountId, "escalation_opened", now, true]
        );
      }

      await client.query("COMMIT");
    } catch (error) {
      await client.query("ROLLBACK").catch(() => {});
      throw error;
    }
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

